use dandelion_commons::{err_dandelion, DandelionError, DandelionResult, MultinodeError};
use prost::bytes::{Buf, Bytes, BytesMut};
use prost::Message;

pub mod client;
pub mod util;

// include autogenerated protobufs
pub mod proto {
    include!(concat!(env!("OUT_DIR"), "/multinode_proto.rs"));
}

// serialization

macro_rules! serialize {
    ($proto_msg:ident) => {{
        let mut buf = Vec::with_capacity($proto_msg.encoded_len());
        $proto_msg.encode(&mut buf).unwrap();
        prost::bytes::Bytes::from(buf)
    }};
}

pub fn serialize_action_status(action_status: proto::ActionStatus) -> Bytes {
    serialize!(action_status)
}

pub fn serialize_node_info(node_info: proto::NodeInfo) -> Bytes {
    serialize!(node_info)
}

pub fn serialize_remote_message(worker_message: proto::RemoteMessage) -> Bytes {
    serialize!(worker_message)
}

pub fn serialize_queue_message(queue_message: proto::QueueMessage) -> Bytes {
    serialize!(queue_message)
}

